/// Convert HTML to plain text using the `html2text` crate.
/// Strips tags, decodes entities, collapses whitespace.
/// Uses a proper HTML parser — safe for any encoding/multibyte content.
fn html_to_text(html: &str) -> String {
    match html2text::from_read(html.as_bytes(), usize::MAX) {
        Ok(text) => text
            .lines()
            .map(str::trim_end)
            .collect::<Vec<_>>()
            .join("\n")
            .trim()
            .to_string(),
        Err(_) => String::new(),
    }
}

/// Truncate a string at a char boundary, not mid-UTF-8.
fn truncate_at_char_boundary(s: &str, max: usize) -> String {
    if s.len() <= max {
        return s.into();
    }
    let mut end = max;
    while end > 0 && !s.is_char_boundary(end) {
        end -= 1;
    }
    s[..end].to_string()
}

#[async_trait]
impl AgentTool for WebFetchTool {
    fn name(&self) -> &str {
        "web_fetch"
    }

